```typescript
// login.dto.ts
import { ApiProperty } from '@nestjs/swagger';

export class LoginDto {
  @ApiProperty({ example: 'user@example.com', description: 'Email de l\'utilisateur' })
  email: string;

  @ApiProperty({ example: 'password123', description: 'Mot de passe', format: 'password' })
  password: string;
}

// auth.controller.ts
import { Controller, Post, Body, HttpCode, HttpStatus } from '@nestjs/common';
import { ApiTags, ApiOperation, ApiResponse, ApiBody } from '@nestjs/swagger';

export class LoginResponseDto {
  @ApiProperty({ example: 'eyJhbGciOiJIUzI1NiIs...' })
  access_token: string;

  @ApiProperty({ example: 'eyJhbGciOiJIUzI1NiIs...' })
  refresh_token: string;
}

@ApiTags('Authentification')
@Controller('auth')
export class AuthController {
  @Post('login')
  @HttpCode(HttpStatus.OK)
  @ApiOperation({ summary: 'Connexion utilisateur', description: 'Authentifie un utilisateur et retourne les tokens JWT' })
  @ApiBody({ type: LoginDto, description: 'Identifiants de connexion' })
  @ApiResponse({ status: 200, description: 'Connexion réussie', type: LoginResponseDto })
  @ApiResponse({ status: 401, description: 'Email ou mot de passe incorrect' })
  async login(@Body() loginDto: LoginDto) {
    return this.authService.login(loginDto);
  }
}
```

**Explications** :
- `@ApiTags()` : regroupe les endpoints par catégorie dans Swagger UI
- `@ApiOperation()` : décrit le but de l'endpoint
- `@ApiBody()` : documente le corps de la requête (avec type DTO)
- `@ApiResponse()` : documente les codes HTTP possibles et leur structure de réponse
- Les `@ApiProperty()` dans les DTOs génèrent automatiquement le schéma des objets

